#include <bits/stdc++.h>
using namespace std;
const int maxn=1e3+5;
struct node {
	vector<int> e;
	int s;
} v[maxn];
int f[maxn][maxn],n,m,t;
void sd(int x) {
	int p=t;
	for(auto i:v[x].e) {
		sd(i);
	}
	t++;
	for(int i=m;i>=1;i--){
		f[t][i]=max(f[t-1][i-1]+v[x].s,f[p][i]);
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	m++;
	for(int i=1,f; i<=n; i++) {
		cin>>f>>v[i].s;
		v[f].e.emplace_back(i);
	}
	sd(0);
	cout<<f[t][m];
	return 0;
}
